# ==================== 1. 发起支付并签约 ====================
@app.route('/subscribe/<plan_id>')
def subscribe(plan_id):
    """
    会员订阅页面 - 发起电脑网站支付并签约
    
    流程：
    1. 用户选择会员套餐
    2. 生成唯一订单号
    3. 调用 alipay.trade.page.pay 发起支付（含签约参数）
    4. 用户跳转支付宝收银台完成支付+签约
    """
    if plan_id not in MEMBER_PLANS:
        return '无效的会员套餐', 400
    
    plan = MEMBER_PLANS[plan_id]
    
    # 生成唯一订单号
    out_trade_no = f"SUB{datetime.now().strftime('%Y%m%d%H%M%S')}{uuid.uuid4().hex[:8]}"
    
    # 保存订单信息（生产环境请存数据库）
    orders[out_trade_no] = {
        'plan_id': plan_id,
        'plan_name': plan['name'],
        'amount': plan['amount'],
        'user_id': 'user_001',  # 实际应从登录会话获取
        'status': 'PENDING',
        'create_time': datetime.now().isoformat(),
    }
    
    # 构建支付请求
    client = get_alipay_client()
    
    model = AlipayTradePagePayModel()
    model.out_trade_no = out_trade_no
    model.product_code = "FAST_INSTANT_TRADE_PAY"
    model.total_amount = plan['amount']
    model.subject = f"{plan['name']}-订阅服务"
    model.body = f"订阅周期：{plan['period']}"
    
    # 设置异步通知地址（必须外网可访问）
    model.notify_url = "https://your-domain.com/alipay/notify"
    # 设置同步返回地址
    model.return_url = "https://your-domain.com/alipay/return"
    
    # ====== 商家扣款签约参数 ======
    # 在 extend_params 中传入签约信息，实现支付并签约
    extend_params = {
        # 周期扣款产品码
        "hb_fq_num": "1",
    }
    
    # 使用 agreement_sign_params 传递签约参数（新版SDK方式）
    # 注意：实际参数名请参考最新SDK文档
    agreement_sign_params = {
        "personal_product_code": "CYCLE_PAY_AUTH_P",  # 周期扣款固定值
        "sign_scene": SCENE_CODE,  # 场景码，需与支付宝BD确认
        "product_code": "GENERAL_WITHHOLDING",
        "period": plan['period'],  # 扣款周期，如 1M
        "period_type": plan['period_type'],  # 周期类型：DAY/MONTH
        "sign_notify_url": "https://your-domain.com/alipay/sign_notify",  # 签约异步通知
        "external_agreement_no": f"AGR{out_trade_no}",  # 商户签约号
    }
    
    # 将签约参数放入业务参数
    # 注意：不同版本SDK传递方式可能不同，请参照实际SDK文档
    model.business_params = json.dumps({
        "agreement_sign_params": agreement_sign_params
    })
    
    request_obj = AlipayTradePagePayRequest(biz_model=model)
    
    # 执行请求，获取form表单HTML
    response = client.page_execute(request_obj, http_method="GET")
    
    # 重定向到支付宝收银台
    return f"""
    <!DOCTYPE html>
    <html>
    <head><title>正在跳转支付宝...</title></head>
    <body>
        <p>正在跳转至支付宝收银台...</p>
        <script>window.location.href = "{response}";</script>
    </body>
    </html>
    """


# ==================== 2. 支付异步通知处理 ====================
@app.route('/alipay/notify', methods=['POST'])
def alipay_notify():
    """
    支付异步通知处理
    
    ⚠️ 安全红线：
    1. 必须先验签，确保通知来自支付宝
    2. 校验 app_id、out_trade_no、total_amount 是否匹配
    3. 处理成功后返回纯文本 "success"
    4. 必须以异步通知结果为准，不能依赖同步跳转
    """
    data = request.form.to_dict()
    
    # 获取签名
    sign = data.pop('sign', None)
    sign_type = data.pop('sign_type', None)
    
    # TODO: 使用支付宝公钥验签（SDK通常自动处理）
    # 这里简化处理，实际应调用SDK验签方法
    
    # 校验关键参数
    app_id = data.get('app_id')
    out_trade_no = data.get('out_trade_no')
    trade_no = data.get('trade_no')
    trade_status = data.get('trade_status')
    total_amount = data.get('total_amount')
    
    # 校验 app_id
    if app_id != ALIPAY_CONFIG['app_id']:
        return 'fail', 400
    
    # 校验订单是否存在
    if out_trade_no not in orders:
        return 'fail', 400
    
    order = orders[out_trade_no]
    
    # 校验金额
    if total_amount != order['amount']:
        return 'fail', 400
    
    # 处理支付结果
    if trade_status in ['TRADE_SUCCESS', 'TRADE_FINISHED']:
        # 支付成功，更新订单状态
        order['status'] = 'PAID'
        order['trade_no'] = trade_no
        order['paid_time'] = datetime.now().isoformat()
        
        # TODO: 激活会员权益、记录订阅信息等
        print(f"[支付成功] 订单: {out_trade_no}, 支付宝流水: {trade_no}")
        
    elif trade_status == 'TRADE_CLOSED':
        order['status'] = 'CLOSED'
        print(f"[订单关闭] 订单: {out_trade_no}")
    
    # 必须返回 success
    return 'success'


# ==================== 3. 签约异步通知处理 ====================
@app.route('/alipay/sign_notify', methods=['POST'])
def alipay_sign_notify():
    """
    签约异步通知处理
    
    用户完成支付并签约后，支付宝会发送签约结果通知
    需保存签约协议号，用于后续自动扣款
    """
    data = request.form.to_dict()
    
    # TODO: 验签
    
    agreement_no = data.get('agreement_no')  # 支付宝协议号
    external_agreement_no = data.get('external_agreement_no')  # 商户签约号
    sign_time = data.get('sign_time')
    invalid_time = data.get('invalid_time')  # 协议失效时间
    
    # 从外部签约号关联到用户
    # external_agreement_no 格式: AGR + out_trade_no
    out_trade_no = external_agreement_no.replace('AGR', '') if external_agreement_no else None
    
    if out_trade_no and out_trade_no in orders:
        user_id = orders[out_trade_no]['user_id']
        
        # 保存签约协议（生产环境请存数据库）
        user_agreements[user_id] = {
            'agreement_no': agreement_no,
            'external_agreement_no': external_agreement_no,
            'sign_time': sign_time,
            'invalid_time': invalid_time,
            'status': 'VALID',
            'plan_id': orders[out_trade_no]['plan_id'],
        }
        
        print(f"[签约成功] 用户: {user_id}, 协议号: {agreement_no}")
    
    return 'success'


# ==================== 4. 发起自动扣款 ====================
@app.route('/deduct/<user_id>')
def deduct_payment(user_id):
    """
    发起自动扣款（周期扣款）
    
    适用场景：
    - 会员到期前，系统自动发起续费扣款
    - 定时任务调用（如每天7:00-22:00之间执行）
    
    ⚠️ 限制：
    - 仅允许北京时间 7:00～22:00 发起
    - 两次扣款间隔建议不小于30天
    - 单笔限额100元
    """
    # 检查是否有有效签约
    if user_id not in user_agreements:
        return jsonify({'error': '用户未签约或签约已失效'}), 400
    
    agreement = user_agreements[user_id]
    
    if agreement['status'] != 'VALID':
        return jsonify({'error': '签约协议已失效'}), 400
    
    # 获取套餐信息
    plan = MEMBER_PLANS.get(agreement['plan_id'])
    if not plan:
        return jsonify({'error': '会员套餐不存在'}), 400
    
    # 生成扣款订单号
    out_trade_no = f"DED{datetime.now().strftime('%Y%m%d%H%M%S')}{uuid.uuid4().hex[:8]}"
    
    # 构建扣款请求
    client = get_alipay_client()
    
    model = AlipayTradePayModel()
    model.out_trade_no = out_trade_no
    model.product_code = "GENERAL_WITHHOLDING"  # 商家扣款固定值
    model.total_amount = plan['amount']
    model.subject = f"{plan['name']}-自动续费"
    
    # 传入签约协议号
    model.agreement_no = agreement['agreement_no']
    
    # 设置异步通知
    model.notify_url = "https://your-domain.com/alipay/notify"
    
    request_obj = AlipayTradePayRequest(biz_model=model)
    
    try:
        response = client.execute(request_obj)
        result = json.loads(response)
        
        if result.get('code') == '10000':
            # 扣款成功
            return jsonify({
                'success': True,
                'trade_no': result.get('trade_no'),
                'out_trade_no': out_trade_no,
                'message': '扣款成功'
            })
        else:
            # 扣款失败
            return jsonify({
                'success': False,
                'error': result.get('sub_msg', '扣款失败'),
                'code': result.get('sub_code')
            }), 400
            
    except Exception as e:
        return jsonify({'error': str(e)}), 500


