def get_alipay_client():
    """获取支付宝客户端实例"""
    alipay_client_config = AlipayClientConfig()
    alipay_client_config.server_url = ALIPAY_CONFIG['gateway_url']
    alipay_client_config.app_id = ALIPAY_CONFIG['app_id']
