@app.route('/agreement/unsign/<user_id>', methods=['POST'])
def unsign_agreement(user_id):
    """用户解约（取消自动续费）"""
    if user_id not in user_agreements:
        return jsonify({'error': '未找到签约记录'}), 404
    
    agreement = user_agreements[user_id]
    
    # 调用支付宝解约接口
    client = get_alipay_client()
    
    # 构建解约请求
    from alipay.aop.api.domain.AlipayUserAgreementUnsignModel import AlipayUserAgreementUnsignModel
    model = AlipayUserAgreementUnsignModel()
    model.agreement_no = agreement['agreement_no']
    model.external_agreement_no = agreement['external_agreement_no']
    
    request_obj = AlipayUserAgreementUnsignRequest(biz_model=model)
    
    try:
        response = client.execute(request_obj)
        result = json.loads(response)
        
        if result.get('code') == '10000':
            agreement['status'] = 'UNSIGNED'
            return jsonify({'success': True, 'message': '解约成功'})
        else:
            return jsonify({
                'success': False,
                'error': result.get('sub_msg', '解约失败')
            }), 400
            
    except Exception as e:
        return jsonify({'error': str(e)}), 500


